mapper.select:
select ipd.*,ui.nickname userName,ui.phone,s.storeName, c.autoPay,c.oldValidityDate,c.validityDate,c.buyCount,c.type as cardType,c.paySum, CASE WHEN ipd.payType = 13 OR ipd.tradeType = 13 OR c.payType = 13 THEN '自动' WHEN ipd.tradeType IN (1, 2, 3) OR c.payType IN (1, 2, 3) THEN '用户' ELSE '后台' END as renewSourceDesc from income_pay_detail ipd LEFT JOIN user_info ui ON ui.userId=ipd.userId LEFT JOIN store_address s ON s.storeId = ipd.storeId LEFT JOIN card_order c ON c.orderNo = ipd.orderNo
ipd.payType in (2,3,4,5,6,9,10,11,13)
AND ui.nickname LIKE concat('%',#{userName},'%')
AND ui.phone LIKE concat('%',#{phone},'%')
AND ipd.orderNo LIKE concat('%',#{orderNo},'%')
AND ipd.payType =#{payType}
AND c.type =#{cardType}
AND c.autoPay =#{autoPay}
AND c.autoPay > 0
AND ipd.tradeType =#{tradeType}
AND s.storeName LIKE concat('%',#{storeName},'%')
AND ipd.storeId = #{storeId}
AND ipd.storeId in (${storeIds})
AND ipd.tradeStatus !=3
AND ipd.tradeStatus =3
AND ipd.transactionTime BETWEEN #{sdate} AND #{edate}
and ipd.incomePayDetailId IN
#{ids}
order by ${sidx} ${order}
order by ipd.createdDate desc
limit #{offset}, #{limit}

select count(1) from income_pay_detail ipd INNER JOIN user_info ui ON ui.userId=ipd.userId LEFT JOIN store_address s ON s.storeId = ipd.storeId
payType in (2,3,4,5,6,9,10,11,13)
AND ui.nickname LIKE concat('%',#{userName},'%')
AND ui.phone LIKE concat('%',#{phone},'%')
AND ipd.orderNo LIKE concat('%',#{orderNo},'%')
AND ipd.payType =#{payType}
AND ipd.tradeType =#{tradeType}
AND s.storeName LIKE concat('%',#{storeName},'%')
AND ipd.storeId = #{storeId}
AND ipd.storeId in (${storeIds})
AND ipd.tradeStatus !=3
AND ipd.tradeStatus =3
AND ipd.transactionTime BETWEEN #{sdate} AND #{edate}

select ipd.incomePayDetailId ,ui.nickname userName,ipd.orderNo,money,ipd.createdDate,ipd.payType
from income_pay_detail ipd
LEFT JOIN user_info ui ON ui.userId = ipd.userId

    payType = 7 and tradeStatus = 3
    
        AND ipd.storeId = #{storeId}
    
    
        AND ipd.storeId in (${storeIds})
    
    
        AND ui.nickname LIKE concat('%',#{userName},'%')
    
    
        AND ipd.orderNo LIKE concat('%',#{orderNo},'%')
    
    
        AND ipd.createdDate BETWEEN #{sdate} AND #{edate}
    


    
        order by ${sidx} ${order}
    
    
        order by ipd.createdDate desc
    


    limit #{offset}, #{limit}

select ipd.incomePayDetailId , s.storeName,ui.nickname userName,ipd.orderNo,money,ipd.createdDate,ipd.payType from income_pay_detail ipd INNER JOIN user_info ui ON ui.userId = ipd.userId INNER JOIN store s ON s.storeId = ipd.storeId
payType = 7 and tradeStatus = 3
AND ui.nickname LIKE concat('%',#{userName},'%')
AND ipd.orderNo LIKE concat('%',#{orderNo},'%')
AND s.storeName LIKE concat('%',#{storeName},'%')
AND ipd.createdDate BETWEEN #{sdate} AND #{edate}
order by ${sidx} ${order}
order by ipd.createdDate desc
limit #{offset}, #{limit}

select sgo.orderNo, sgo.barCode, sgo.name, sgo.price,sgo.style,sgo.num
  from income_pay_detail ipd inner join store_goods_order sgo on sgo.orderNo=ipd.orderNo
  where ipd.incomePayDetailId=#{id}

select ipd.incomePayDetailId, s.storeName,ui.nickname,ipd.money, ui.phone, ipd.orderNo,ipd.createdDate, (select u.nickname from user_info u where u.userId=ipd.anotherId) as takeName, (select us.phone from user_info us where us.userId=ipd.anotherId) as takePhone from income_pay_detail ipd INNER JOIN user_info ui ON ui.userId = ipd.userId INNER JOIN store s ON s.storeId = ipd.storeId
payType = 12
AND ipd.storeId = #{storeId}
AND ipd.storeId in (${storeIds})
AND ui.nickname LIKE concat('%',#{userName},'%')
AND ipd.orderNo LIKE concat('%',#{orderNo},'%')
AND s.storeName LIKE concat('%',#{storeName},'%')
AND ui.phone LIKE concat('%',#{phone},'%')
AND ipd.createdDate BETWEEN #{sdate} AND #{edate}
order by ${sidx} ${order}
order by ipd.createdDate desc
limit #{offset}, #{limit}
